content.content:
1	/**
2	 * Resolve an instrument directory from root + name + version.
3	 *
4	 * Supports three resolution strategies:
5	 *   1. Explicit path: --instrument /full/path/to/version/dir
6	 *   2. Name + version: --instrument-name foo --instrument-version v1
7	 *      resolves to {root}/foo/v1
8	 *   3. Name only: --instrument-name foo
9	 *      auto-selects version if exactly one exists; errors if multiple
10	 *
11	 * The instrument root defaults to experiments/instruments/ relative
12	 * to the project root, overridable via --instrument-root.
13	 */
14	
15	import { existsSync, readdirSync, statSync } from 'node:fs';
16	import { join, resolve } from 'node:path';
