1	/**
2	 * The Animator — public types.
3	 *
4	 * These types form the contract between The Animator apparatus and all
5	 * callers (summon relay, nsg consult, etc.). No implementation details.
6	 *
7	 * See: docs/specification.md (animator)
8	 */
9	import type { AnimaWeave } from '@shardworks/loom-apparatus';
10	import type { ResolvedTool } from '@shardworks/tools-apparatus';
11	/** A chunk of output from a running session. */
12	export type SessionChunk = {
13	    type: 'text';
14	    text: string;
15	} | {
16	    type: 'tool_use';
17	    tool: string;
18	} | {
19	    type: 'tool_result';
20	    tool: string;
21	};
22	export interface AnimateRequest {
23	    /**
24	     * Optional pre-generated session id. When provided, the Animator uses
25	     * this id instead of generating a new one. Used by summon() to make the
26	     * session id available on the handle before the Loom weave resolves.
27	     */
28	    sessionId?: string;
29	    /** The anima weave from The Loom (composed identity context). */
30	    context: AnimaWeave;
31	    /**
32	     * The work prompt — what the anima should do.
33	     * Passed directly to the session provider as the initial prompt.
34	     * This bypasses The Loom — it is not a composition concern.
35	     */
36	    prompt?: string;
37	    /**
38	     * Working directory for the session.
39	     * The session provider launches the AI process here.
40	     */
41	    cwd: string;
42	    /**
43	     * Optional conversation id to resume a multi-turn conversation.
44	     * If provided, the session provider resumes the existing conversation
45	     * rather than starting a new one.
46	     */
47	    conversationId?: string;
48	    /**
49	     * Caller-supplied metadata recorded alongside the session.
50	     * The Animator stores this as-is — it does not interpret the contents.
51	     */
52	    metadata?: Record<string, unknown>;
53	    /**
54	     * Enable streaming output. When true, the returned `chunks` iterable
55	     * yields output as the session produces it. When false (default), the
56	     * `chunks` iterable completes immediately with no items.
57	     *
58	     * Either way, the return shape is the same: `{ chunks, result }`.
59	     */
60	    streaming?: boolean;
61	    /**
62	     * Task-layer environment variables. Overrides the identity-layer
63	     * environment from the AnimaWeave when keys collide. Spread into the
64	     * spawned process environment.
65	     */
66	    environment?: Record<string, string>;
67	}
68	export interface SessionResult {
69	    /** Unique session id (generated by The Animator). */
70	    id: string;
71	    /** Terminal status. */
72	    status: 'completed' | 'failed' | 'timeout';
73	    /** When the session started (ISO-8601). */
74	    startedAt: string;
75	    /** When the session ended (ISO-8601). */
76	    endedAt: string;
77	    /** Wall-clock duration in milliseconds. */
78	    durationMs: number;
79	    /** Provider name (e.g. 'claude-code'). */
80	    provider: string;
81	    /** Numeric exit code from the provider process. */
82	    exitCode: number;
83	    /** Error message if failed. */
84	    error?: string;
85	    /** Conversation id (for multi-turn resume). */
86	    conversationId?: string;
87	    /** Session id from the provider (e.g. for --resume). */
88	    providerSessionId?: string;
89	    /** Token usage from the provider, if available. */
90	    tokenUsage?: TokenUsage;
91	    /** Cost in USD from the provider, if available. */
92	    costUsd?: number;
93	    /** Caller-supplied metadata, recorded as-is. */
94	    metadata?: Record<string, unknown>;
95	    /**
96	     * The final assistant text from the session.
97	     * Extracted by the Animator from the provider's transcript.
98	     * Useful for programmatic consumers that need the session's conclusion
99	     * without parsing the full transcript (e.g. the Spider's review collect step).
100	     */
101	    output?: string;
102	}
103	export interface TokenUsage {
104	    inputTokens: number;
105	    outputTokens: number;
106	    cacheReadTokens?: number;
107	    cacheWriteTokens?: number;
108	}
109	export interface SummonRequest {
110	    /**
111	     * The work prompt — what the anima should do.
112	     * Passed directly to the session provider as the initial prompt.
113	     */
114	    prompt: string;
115	    /**
116	     * The role to summon (e.g. 'artificer', 'scribe').
117	     * Passed to The Loom for context composition and recorded in session metadata.
118	     */
119	    role?: string;
120	    /**
121	     * Working directory for the session.
122	     * The session provider launches the AI process here.
123	     */
124	    cwd: string;
125	    /**
126	     * Optional conversation id to resume a multi-turn conversation.
127	     */
128	    conversationId?: string;
129	    /**
130	     * Additional metadata to record alongside the session.
131	     * Merged with auto-generated metadata (trigger: 'summon', role).
132	     */
133	    metadata?: Record<string, unknown>;
134	    /**
135	     * Enable streaming output. When true, the returned `chunks` iterable
136	     * yields output as the session produces it. When false (default), the
137	     * `chunks` iterable completes immediately with no items.
138	     */
139	    streaming?: boolean;
140	    /**
141	     * Task-layer environment variables. Overrides the identity-layer
142	     * environment from the AnimaWeave when keys collide. Spread into the
143	     * spawned process environment.
144	     */
145	    environment?: Record<string, string>;
146	}
147	/** The return value from animate() and summon(). */
148	export interface AnimateHandle {
149	    /**
150	     * Session ID, available immediately after launch — before the session
151	     * completes. Callers that only need to know the session was launched
152	     * (e.g. quick engines returning `{ status: 'launched', sessionId }`)
153	     * can return without awaiting `result`.
154	     */
155	    sessionId: string;
156	    /**
157	     * Async iterable of output chunks from the session. When streaming is
158	     * disabled (the default), this iterable completes immediately with no
159	     * items. When streaming is enabled, it yields chunks as the session
160	     * produces output.
161	     */
162	    chunks: AsyncIterable<SessionChunk>;
163	    /**
164	     * Promise that resolves to the final SessionResult after the session
165	     * completes (or fails/times out) and the result is recorded to The Stacks.
166	     */
167	    result: Promise<SessionResult>;
168	}
169	export interface AnimatorApi {
170	    /**
171	     * Summon an anima — compose context via The Loom and launch a session.
172	     *
173	     * This is the high-level "make an anima do a thing" entry point.
174	     * Internally calls The Loom for context composition (passing the role),
175	     * then animate() for session launch and recording. The work prompt
176	     * bypasses the Loom and goes directly to the provider.
177	     *
178	     * Requires The Loom apparatus to be installed. Throws if not available.
179	     *
180	     * Auto-populates session metadata with `trigger: 'summon'` and `role`.
181	     *
182	     * Returns synchronously — the async work lives inside `result` and `chunks`.
183	     */
184	    summon(request: SummonRequest): AnimateHandle;
185	    /**
186	     * Animate a session — launch an AI process with the given context.
187	     *
188	     * This is the low-level entry point for callers that compose their own
189	     * AnimaWeave (e.g. The Parlour for multi-turn conversations).
190	     *
191	     * Records the session result to The Stacks before `result` resolves.
192	     *
193	     * Set `streaming: true` on the request to receive output chunks as the
194	     * session runs. When streaming is disabled (default), the `chunks`
195	     * iterable completes immediately with no items.
196	     *
197	     * Returns synchronously — the async work lives inside `result` and `chunks`.
198	     */
199	    animate(request: AnimateRequest): AnimateHandle;
200	}
201	/**
202	 * A session provider — pluggable backend that knows how to launch and
203	 * communicate with a specific AI system.
204	 *
205	 * Implemented as an apparatus plugin whose `provides` object satisfies
206	 * this interface. The Animator discovers the provider via guild config:
207	 * `guild.json["animator"]["sessionProvider"]` names the plugin id.
208	 *
209	 * The provider always returns `{ chunks, result }` — the same shape as
210	 * AnimateHandle. When `config.streaming` is true, the provider MAY yield
211	 * output chunks as the session runs. When false (or when the provider
212	 * does not support streaming), the chunks iterable completes immediately
213	 * with no items. The Animator does not branch on streaming capability —
214	 * it passes the flag through and trusts the provider to do the right thing.
215	 */
216	export interface AnimatorSessionProvider {
217	    /** Human-readable name (e.g. 'claude-code'). */
218	    name: string;
219	    /**
220	     * Launch a session. Returns `{ chunks, result }` synchronously.
221	     *
222	     * The `result` promise resolves when the AI process exits.
223	     * The `chunks` async iterable yields output when `config.streaming`
224	     * is true and the provider supports streaming; otherwise it completes
225	     * immediately with no items.
226	     *
