execution:
  model: claude-opus-4-6
  effort: medium
  max_turns: 1
  tools: disabled
  runs: 3
  min_successful_runs: 2

parameters:
  commission:  { required: true, description: "Commission/writ ID" }
  repo:        { required: true, description: "Path to git repo" }
  spec_file:   { required: true, description: "Path to commission spec file" }
