  commit:      { required: false, description: "Override: end of commit range" }

setup: extractors/resolve-commits.sh

inputs:
  SPEC:           { extractor: extractors/spec.sh }
  DIFF:           { extractor: extractors/diff.sh }
  FULL_FILES:     { extractor: extractors/full-files.sh }
  CONTEXT_FILES:  { extractor: extractors/context-files.sh }
  FILE_TREE:      { extractor: extractors/file-tree.sh }
  API_SURFACE:    { extractor: extractors/api-surface.sh }

prompts:
  system: prompts/system.md
  user: prompts/user.md

output:
  format: yaml
  dimensions:
    - { name: utility_reuse,     type: integer, range: [1, 5] }
    - { name: module_placement,  type: integer, range: [1, 5] }
