2	 * Parse and validate LLM output against the instrument's output schema.
3	 *
4	 * The LLM response is expected to contain a YAML block (possibly inside
5	 * a markdown code fence). The parser extracts the YAML, validates
6	 * dimension scores against declared ranges, and extracts qualitative
7	 * fields.
8	 */
9	
10	import yaml from 'js-yaml';
11	import type { OutputSchema, ParsedRun, DimensionDef, CompositeDef } from './types.ts';
12	
13	/**
14	 * Extract a YAML block from an LLM response.
15	 *
16	 * Handles two cases:
17	 *   1. Response wrapped in ```yaml ... ``` code fence
18	 *   2. Raw YAML (the whole response is YAML)
19	 */
20	function extractYaml(response: string): string {
21	  // Try to find a YAML code fence first
22	  const fenceMatch = response.match(/```(?:yaml)?\s*\n([\s\S]*?)\n\s*```/);
23	  if (fenceMatch) return fenceMatch[1];
24	
25	  // Fall back to treating the whole response as YAML
26	  return response.trim();
27	}
28	
29	/**
30	 * Compute composite score from dimension values.
31	 */
32	function computeComposite(
33	  dimensions: Record<string, number>,
34	  compositeDef: CompositeDef,
35	  dimensionDefs: DimensionDef[],
36	): number {
37	  const names =
38	    compositeDef.dimensions === 'all'
39	      ? dimensionDefs.map((d) => d.name)
40	      : compositeDef.dimensions;
41	
42	  const values = names.map((name) => dimensions[name]).filter((v) => v != null);
43	  if (values.length === 0) return 0;
44	
45	  // Only 'mean' is supported currently
46	  const sum = values.reduce((a, b) => a + b, 0);
47	  return round(sum / values.length, 2);
48	}
49	
50	function round(n: number, decimals: number): number {
51	  const factor = 10 ** decimals;
52	  return Math.round(n * factor) / factor;
53	}
54	
55	/**
56	 * Parse a single LLM run response against the output schema.
57	 *
58	 * Returns null if the response cannot be parsed or validated.
59	 */
60	export function parseRun(response: string, schema: OutputSchema): ParsedRun | null {
61	  const yamlText = extractYaml(response);
62	
63	  let doc: Record<string, unknown>;
64	  try {
65	    const parsed = yaml.load(yamlText);
66	    if (!parsed || typeof parsed !== 'object') return null;
67	    doc = parsed as Record<string, unknown>;
68	  } catch {
69	    return null;
70	  }
71	
72	  // Extract dimensions — may be nested under a "dimensions" key or flat
73	  const dimSource = (
74	    doc.dimensions && typeof doc.dimensions === 'object'
75	      ? doc.dimensions
76	      : doc
77	  ) as Record<string, unknown>;
78	
79	  const dimensions: Record<string, number> = {};
80	  for (const def of schema.dimensions) {
81	    const raw = dimSource[def.name];
82	    if (raw == null) return null;
83	
84	    const value = Number(raw);
85	    if (!Number.isInteger(value)) return null;
86	    if (value < def.range[0] || value > def.range[1]) return null;
87	
88	    dimensions[def.name] = value;
89	  }
90	
91	  // Extract qualitative fields
92	  const qualitative: Record<string, string> = {};
93	  for (const def of schema.qualitative) {
94	    const raw = doc[def.name];
95	    qualitative[def.name] = raw != null ? String(raw).trim() : '';
96	  }
97	
98	  const composite = computeComposite(dimensions, schema.composite, schema.dimensions);
99	
100	  return { dimensions, qualitative, composite };
101	}
